interface HeaderBarProps {
    title: string;
}

interface WindowProps {
    children: React.ReactNode;
}

function HeaderBar({ title }: HeaderBarProps){
    return(
        <div className="flex justify-between gap-3 p-3 bg-slate-900 rounded-tl-2xl rounded-tr-2xl">
            {/* Botões da janela */}
            <span className="p-2 bg-[#eba0ac] hover:bg-[#f38ba8]"></span>
            <span className="p-2 bg-[#f9e2af] hover:bg-[#fab387]"></span>
            <span className="p-2 bg-[#a6e3a1] hover:bg-[#7eb892]"></span>
            {/* Titulo da janela*/}
            <h3>{title}</h3>
        </div>
    )
}

function Window({ children, title }: WindowProps & HeaderBarProps) {
    return (
        <div className="rounded-md bg-[#1B1C2C]">
            <HeaderBar title={title} />
            <div className="p-4">
                {children}
            </div>
        </div>
    )
}

export default Window;